-- Migration: 006_create_stock_table.sql\n-- Date: 2026-06-16\n\nCREATE TABLE stock (\n    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),\n    property_id UUID NOT NULL REFERENCES properties(id) ON DELETE CASCADE,\n    item_name VARCHAR(255) NOT NULL,\n    category VARCHAR(50), -- 'fertilizer', 'pesticide', etc\n    quantity DECIMAL(10, 2),\n    unit VARCHAR(20), -- 'kg', 'liters', etc\n    minimum_quantity DECIMAL(10, 2),\n    expiry_date DATE,\n    last_updated TIMESTAMP DEFAULT CURRENT_TIMESTAMP\n);\n\nCREATE INDEX idx_stock_property_id ON stock(property_id);\nCREATE INDEX idx_stock_category ON stock(category);\n